      axis.title = ggplot2::element_text(size = 11, color = COL_TEXT),
      axis.text = ggplot2::element_text(size = 10, color = COL_TEXT),
      plot.title = ggplot2::element_text(size = 12, face = "bold", hjust = 0, color = COL_TEXT),
      plot.subtitle = ggplot2::element_text(size = 10, hjust = 0, color = "grey35"),
