save_pub_pdf <- function(plot_obj, filename, dims = FIG_DIMS$wide_medium) {
  ggplot2::ggsave(
    filename = filename,
    plot = plot_obj,
    width = dims[1],
    height = dims[2],
    units = "in",
    device = grDevices::cairo_pdf,
    dpi = 300,
    bg = "white",
    limitsize = FALSE
  )
}

