    filename = filename,
    plot = plot_obj,
    width = dims[1],
    height = dims[2],
    units = "in",
    dpi = 600,
    bg = "white",
    limitsize = FALSE
  )
}

save_pub_both <- function(plot_obj, filename_base, dims = FIG_DIMS$wide_medium) {
