safe_read_csv <- function(file) {
  if (!file.exists(file)) stop("No existe el archivo:\n", file, call. = FALSE)
  readr::read_csv(file, show_col_types = FALSE)
}

safe_write_csv <- function(x, file) {
  dir.create(dirname(file), recursive = TRUE, showWarnings = FALSE)
  readr::write_csv(x, file)
}

clean_text_na <- function(x) {
  x <- as.character(x)
  x <- trimws(x)
  x[x %in% c("", "NA", "NaN", "NULL", "null", "N/A", "nan")] <- NA_character_
  x
}

safe_numeric <- function(x) {
  suppressWarnings(as.numeric(x))
}

standardize_module_name <- function(x) {
  x <- as.character(x)
  x <- trimws(x)
  gsub("^ME", "", x)
}

add_sig_stars <- function(q) {
  dplyr::case_when(
    is.na(q)  ~ "",
    q < 0.001 ~ "***",
    q < 0.01  ~ "**",
    q < 0.05  ~ "*",
    TRUE      ~ ""
  )
}

make_module_display_labels <- function(modules, show_internal_name = TRUE) {
  modules <- as.character(modules)
  if (show_internal_name) {
    labels <- paste0("M", seq_along(modules), " / ", modules)
  } else {
    labels <- paste0("M", seq_along(modules))
  }
  stats::setNames(labels, modules)
}

convert_pdf_first_page_to_png <- function(pdf_file, png_file, dpi = 300) {
  if (!file.exists(pdf_file)) stop("No existe el PDF del dendrograma:\n", pdf_file, call. = FALSE)

  tmp_pattern <- file.path(dirname(png_file), "tmp_dendro_page_%d.png")

  out_files <- suppressWarnings(
    pdftools::pdf_convert(
      pdf = pdf_file,
      format = "png",
      pages = 1,
      filenames = tmp_pattern,
      dpi = dpi
    )
  )

  if (length(out_files) == 0 || !file.exists(out_files[1])) {
    stop("No se pudo convertir el PDF del dendrograma a PNG.", call. = FALSE)
  }

  file.copy(out_files[1], png_file, overwrite = TRUE)
  invisible(png_file)
}

panel_from_png <- function(png_file, crop_white = TRUE, pad_px = 18) {
  if (!file.exists(png_file)) stop("No existe el PNG esperado:\n", png_file, call. = FALSE)

  img <- png::readPNG(png_file)

  # Editorial fix for panel a:
  # the WGCNA dendrogram PDF often carries large white margins, making panel a
  # look visually smaller than panels b-d. We crop near-white margins before
  # placing it in the composite so panels a-d occupy comparable visual space.
  if (crop_white) {
    rgb <- img[, , seq_len(min(3, dim(img)[3])), drop = FALSE]
    nonwhite <- apply(rgb < 0.985, c(1, 2), any)
    if (any(nonwhite)) {
      rr <- range(which(rowSums(nonwhite) > 0))
      cc <- range(which(colSums(nonwhite) > 0))
      rr <- pmax(1, c(rr[1] - pad_px, rr[2] + pad_px))
      cc <- pmax(1, c(cc[1] - pad_px, cc[2] + pad_px))
      rr[2] <- min(dim(img)[1], rr[2])
      cc[2] <- min(dim(img)[2], cc[2])
      img <- img[rr[1]:rr[2], cc[1]:cc[2], , drop = FALSE]
    }
  }

  cowplot::ggdraw() +
    cowplot::draw_image(img, x = 0.5, y = 0.5, hjust = 0.5, vjust = 0.5, scale = 0.98) +
    theme(
      plot.margin = margin(2, 2, 2, 2),
      plot.background = element_rect(fill = "white", color = NA)
    )
}

blank_placeholder <- function(title = "No data available", subtitle = NULL) {
  p <- ggplot() +
    annotate("text", x = 0.5, y = 0.58, label = title, size = 5, fontface = "bold") +
    coord_cartesian(xlim = c(0, 1), ylim = c(0, 1)) +
    theme_void_card()

  if (!is.null(subtitle)) {
    p <- p + annotate("text", x = 0.5, y = 0.42, label = subtitle, size = 4)
  }

  p
}

wrap_term <- function(x, width = 30) {
  stringr::str_wrap(as.character(x), width = width)
}

to_sentence_case <- function(x) {
  x <- as.character(x)
  x <- stringr::str_squish(x)
  out <- tolower(x)
  out <- paste0(toupper(substr(out, 1, 1)), substr(out, 2, nchar(out)))

  # Preserve standard abbreviations and symbols used in the manuscript.
  out <- stringr::str_replace_all(out, "ecm", "ECM")
  out <- stringr::str_replace_all(out, "dna", "DNA")
  out <- stringr::str_replace_all(out, "rna", "RNA")
  out <- stringr::str_replace_all(out, "cam", "CAM")
  out
}

shorten_pathway_label <- function(x) {
  x <- as.character(x)
  x <- stringr::str_replace_all(x, "_", " ")

  # Curated label harmonization for the main figure.
  # These labels are intentionally short and sentence-case. They describe
  # module-level enrichment only; they do not imply that the pathway itself is
  # increased or decreased in AD.
  x <- stringr::str_replace_all(x, regex("Developmental Cell Lineages of the Integumentary System", ignore_case = TRUE), "Developmental cell lineages")
  x <- stringr::str_replace_all(x, regex("Metabolism of xenobiotics by cytochrome P450", ignore_case = TRUE), "Xenobiotic metabolism")
  x <- stringr::str_replace_all(x, regex("Differentiation of Keratinocytes in Interfollicular Epidermis and Mammalian Skin", ignore_case = TRUE), "Keratinocyte differentiation")
  x <- stringr::str_replace_all(x, regex("Cell adhesion molecule \\(CAM\\) interaction", ignore_case = TRUE), "Cell adhesion molecule interaction")
  x <- stringr::str_replace_all(x, regex("Cell adhesion molecules", ignore_case = TRUE), "Cell adhesion molecule interaction")
  x <- stringr::str_replace_all(x, regex("Extracellular matrix organization", ignore_case = TRUE), "ECM organization")
  x <- stringr::str_replace_all(x, regex("Regulation of cellular response to growth factor stimulus", ignore_case = TRUE), "Growth-factor response")
  x <- stringr::str_replace_all(x, regex("Chemical carcinogenesis - DNA adducts", ignore_case = TRUE), "Chemical carcinogenesis")

  x <- stringr::str_squish(x)
  x <- to_sentence_case(x)
  x <- stringr::str_trunc(x, width = 42, side = "right", ellipsis = "…")
  x
}

