get_hub_label <- function(df) {
  if ("Protein_Display" %in% names(df)) {
    out <- df$Protein_Display
  } else if ("Protein_Name" %in% names(df)) {
    out <- df$Protein_Name
  } else if ("EntrezGeneSymbol" %in% names(df)) {
    out <- df$EntrezGeneSymbol
  } else {
    out <- rep(NA_character_, nrow(df))
  }

  out <- as.character(out)

  if ("EntrezGeneSymbol" %in% names(df)) {
    eg <- as.character(df$EntrezGeneSymbol)
    out[is.na(out) | out == ""] <- eg[is.na(out) | out == ""]
  }

  out
}

find_hub_file <- function(module_name) {
  candidate <- file.path(HUB_DIR, paste0("top_hubs_", module_name, ".csv"))
  if (file.exists(candidate)) return(candidate)

  all_files <- list.files(path = HUB_DIR, pattern = "\\.csv$", full.names = TRUE)
  matched <- all_files[
    grepl(paste0("^top_hubs_", module_name, "\\.csv$"), basename(all_files), ignore.case = TRUE)
  ]

  if (length(matched) == 0) return(NULL)
  matched[1]
}

find_enrichment_files <- function(module_name) {
  # Compatible with Script 03 v3/v4 naming: *_all_terms.csv
  files_go <- list.files(
    path = ENRICH_GO_DIR,
    pattern = paste0("^enrichment_GO_BP_", module_name, "(_all_terms)?\\.csv$"),
    full.names = TRUE,
    ignore.case = TRUE
  )

  files_kegg <- list.files(
    path = ENRICH_KEGG_DIR,
    pattern = paste0("^enrichment_KEGG_", module_name, "(_all_terms)?\\.csv$"),
    full.names = TRUE,
    ignore.case = TRUE
  )

  files_react <- list.files(
    path = ENRICH_REACT_DIR,
    pattern = paste0("^enrichment_Reactome_", module_name, "(_all_terms)?\\.csv$"),
    full.names = TRUE,
    ignore.case = TRUE
  )

  list(
    GO_BP = files_go,
    KEGG = files_kegg,
    Reactome = files_react
  )
}

standardize_enrichment_df <- function(df, library_name, module_name) {
  if (is.null(df) || nrow(df) == 0) return(NULL)

  desc_candidates <- c("Description", "Term", "term", "Pathway", "pathway", "ID", "name", "Name")
  found_desc <- intersect(desc_candidates, names(df))
  if (length(found_desc) == 0) return(NULL)
  if (found_desc[1] != "Description") {
    df <- df %>% rename(Description = all_of(found_desc[1]))
  }

  padj_candidates <- c("p.adjust", "adj.P.Val", "padj", "FDR", "qvalue", "p_adj", "Adjusted.P.value", "adjusted_p_value")
  found_padj <- intersect(padj_candidates, names(df))

  if (length(found_padj) == 0) {
    pval_candidates <- c("pvalue", "p.value", "P.Value", "P_value")
    found_pval <- intersect(pval_candidates, names(df))
    if (length(found_pval) == 0) return(NULL)
    df <- df %>% rename(p.adjust = all_of(found_pval[1]))
  } else {
    if (found_padj[1] != "p.adjust") {
      df <- df %>% rename(p.adjust = all_of(found_padj[1]))
    }
  }

  if (!"Count" %in% names(df)) {
    count_candidates <- c("Gene.Count", "gene_count", "Count")
    found_count <- intersect(count_candidates, names(df))
    if (length(found_count) > 0 && found_count[1] != "Count") {
      df <- df %>% rename(Count = all_of(found_count[1]))
    } else if ("geneID" %in% names(df)) {
      df$Count <- sapply(strsplit(as.character(df$geneID), "/"), length)
    } else {
      df$Count <- 1
    }
  }

  df %>%
    mutate(
      Description = as.character(Description),
      p.adjust = suppressWarnings(as.numeric(p.adjust)),
      Count = suppressWarnings(as.numeric(Count)),
      Library = library_name,
      Module = module_name
    ) %>%
    filter(
      !is.na(Description), Description != "",
      !is.na(p.adjust), is.finite(p.adjust),
      p.adjust > 0,
      p.adjust < 0.05
    ) %>%
    mutate(
      Description = gsub("_", " ", Description),
      neglog10 = -log10(p.adjust)
    )
}

get_top_hubs <- function(module_name, n = 5) {
  file <- find_hub_file(module_name)

  if (is.null(file) || !file.exists(file)) {
    warning("No existe archivo de hubs para módulo: ", module_name)
    return(NULL)
  }

  df <- safe_read_csv(file)

  if (!"abs_kME" %in% names(df)) {
    if ("kME" %in% names(df)) {
      df <- df %>% dplyr::mutate(abs_kME = abs(kME))
    } else if ("MM" %in% names(df)) {
      df <- df %>% dplyr::mutate(abs_kME = abs(MM))
    } else {
      warning("No se encontró abs_kME/kME/MM en hubs para módulo: ", module_name)
      return(NULL)
    }
  }

  if (!"hub_rank" %in% names(df)) {
    df <- df %>%
      dplyr::arrange(dplyr::desc(abs_kME)) %>%
      dplyr::mutate(hub_rank = dplyr::row_number())
  }

  if (!"EntrezGeneSymbol" %in% names(df)) {
    df$EntrezGeneSymbol <- NA_character_
  }

  df %>%
    dplyr::mutate(
      label = get_hub_label(.),
      label = as.character(label),
      EntrezGeneSymbol = clean_text_na(EntrezGeneSymbol),
      abs_kME = suppressWarnings(as.numeric(abs_kME)),
      hub_rank = suppressWarnings(as.numeric(hub_rank))
    ) %>%
    dplyr::filter(!is.na(label), label != "") %>%
    dplyr::arrange(dplyr::desc(abs_kME), hub_rank) %>%
    dplyr::slice(seq_len(min(n, nrow(.)))) %>%
    dplyr::mutate(Module = module_name)
}

get_top_pathways_curated <- function(module_name,
                                     n_total = TOP_PATHWAYS_N,
                                     max_per_library = MAX_TERMS_PER_LIBRARY) {
  files_list <- find_enrichment_files(module_name)
  all_tbls <- list()

  for (lib in names(files_list)) {
    lib_files <- files_list[[lib]]
    if (length(lib_files) == 0) next

    df_list <- lapply(lib_files, function(f) {
      tryCatch(readr::read_csv(f, show_col_types = FALSE), error = function(e) NULL)
    })

    df_list <- df_list[!sapply(df_list, is.null)]
    if (length(df_list) == 0) next

    df_lib <- bind_rows(df_list)
    df_lib <- standardize_enrichment_df(df_lib, library_name = lib, module_name = module_name)

    if (is.null(df_lib) || nrow(df_lib) == 0) next

    df_lib <- df_lib %>%
      arrange(p.adjust) %>%
      distinct(Description, .keep_all = TRUE) %>%
      slice(seq_len(min(max_per_library, nrow(.))))

    all_tbls[[lib]] <- df_lib
  }

  if (length(all_tbls) == 0) return(NULL)

  bind_rows(all_tbls) %>%
    arrange(p.adjust) %>%
    distinct(Description, .keep_all = TRUE) %>%
    slice(seq_len(min(n_total, nrow(.))))
}

