build_real_network <- function(module_name) {

  genes_all <- colnames(datExpr_clean)

  hub_seed <- get_top_hubs(module_name, n = N_SEED_HUBS)

  if (is.null(hub_seed) || nrow(hub_seed) == 0) {
    return(blank_placeholder("No hubs available", "TOM-based network could not be constructed"))
  }

  hub_seed <- hub_seed %>%
    filter(!is.na(EntrezGeneSymbol), EntrezGeneSymbol != "") %>%
    distinct(EntrezGeneSymbol, .keep_all = TRUE)

  if (nrow(hub_seed) == 0) {
    return(blank_placeholder("No valid hub symbols", "Hub table has no usable EntrezGeneSymbol"))
  }

  module_genes <- gene_module_tbl %>%
    filter(Module == module_name) %>%
    mutate(EntrezGeneSymbol = clean_text_na(EntrezGeneSymbol)) %>%
    filter(!is.na(EntrezGeneSymbol), EntrezGeneSymbol != "") %>%
    distinct(EntrezGeneSymbol, .keep_all = TRUE)

  module_idx <- match(module_genes$EntrezGeneSymbol, genes_all)
  valid_mod <- which(!is.na(module_idx))

  if (length(valid_mod) < 2) {
    return(blank_placeholder("Insufficient module overlap", "Module genes not found in datExpr_clean"))
  }

  module_genes_valid <- module_genes$EntrezGeneSymbol[valid_mod]
  module_idx_valid   <- module_idx[valid_mod]

  hub_idx <- match(hub_seed$EntrezGeneSymbol, genes_all)
  valid_hub <- which(!is.na(hub_idx))

  if (length(valid_hub) < 2) {
    return(blank_placeholder("Insufficient TOM overlap", "Seed hubs not found in datExpr_clean"))
  }

  hub_seed <- hub_seed[valid_hub, , drop = FALSE]
  hub_idx  <- hub_idx[valid_hub]

  neighbor_symbols <- c()

  for (i in seq_along(hub_idx)) {
    tom_vec <- TOM[hub_idx[i], module_idx_valid]
    names(tom_vec) <- module_genes_valid

    tom_vec <- tom_vec[names(tom_vec) != hub_seed$EntrezGeneSymbol[i]]
    tom_vec <- sort(tom_vec, decreasing = TRUE)

    if (length(tom_vec) > 0) {
      neighbor_symbols <- c(
        neighbor_symbols,
        names(tom_vec)[seq_len(min(N_NEIGHBORS_PER_HUB, length(tom_vec)))]
      )
    }
  }

  neighbor_symbols <- unique(neighbor_symbols)

  hub_nodes <- hub_seed %>%
    transmute(
      EntrezGeneSymbol,
      label = ifelse(is.na(label) | label == "", EntrezGeneSymbol, label),
      abs_kME = abs_kME,
      hub_rank = hub_rank,
      node_type = "hub"
    )

  neighbor_nodes <- tibble(
    EntrezGeneSymbol = neighbor_symbols
  ) %>%
    filter(!EntrezGeneSymbol %in% hub_nodes$EntrezGeneSymbol) %>%
    left_join(
      gene_module_tbl %>%
        filter(Module == module_name) %>%
        transmute(
          EntrezGeneSymbol = clean_text_na(EntrezGeneSymbol),
          label = get_hub_label(.)
        ) %>%
        distinct(EntrezGeneSymbol, .keep_all = TRUE),
      by = "EntrezGeneSymbol"
    ) %>%
    mutate(
      label = ifelse(is.na(label) | label == "", EntrezGeneSymbol, label),
      abs_kME = NA_real_,
      hub_rank = NA_real_,
      node_type = "neighbor"
    )

  node_tbl <- bind_rows(hub_nodes, neighbor_nodes) %>%
    distinct(EntrezGeneSymbol, .keep_all = TRUE) %>%
    mutate(
      abs_kME = ifelse(is.na(abs_kME), 0.45, abs_kME),
      node_fill = ifelse(node_type == "hub", MODULE_COLORS[module_name], "grey92")
    )

  idx <- match(node_tbl$EntrezGeneSymbol, genes_all)
  valid <- which(!is.na(idx))

  if (length(valid) < 2) {
    return(blank_placeholder("Insufficient final node overlap", "Expanded network not found in datExpr_clean"))
  }

  node_tbl <- node_tbl[valid, , drop = FALSE]
  idx <- idx[valid]

  tom_sub <- TOM[idx, idx, drop = FALSE]
  diag(tom_sub) <- 0

  edge_df <- expand.grid(
    from_idx = seq_len(nrow(tom_sub)),
    to_idx   = seq_len(ncol(tom_sub)),
    KEEP.OUT.ATTRS = FALSE,
    stringsAsFactors = FALSE
  ) %>%
    mutate(
      weight = as.numeric(tom_sub[cbind(from_idx, to_idx)])
    ) %>%
    filter(from_idx < to_idx) %>%
    filter(!is.na(weight), is.finite(weight))

  edge_df_thr <- edge_df %>%
    filter(weight >= EDGE_TOM_THRESHOLD) %>%
    arrange(desc(weight))

  if (nrow(edge_df_thr) < MIN_EDGES_IF_SPARSE) {
    edge_df_thr <- edge_df %>%
      arrange(desc(weight)) %>%
      slice(seq_len(min(MIN_EDGES_IF_SPARSE, nrow(.))))
  }

  if (nrow(edge_df_thr) < 10) {
    edge_df_thr <- edge_df %>%
      arrange(desc(weight)) %>%
      slice(seq_len(min(60, nrow(.))))
  }

  edge_df_thr <- edge_df_thr %>%
    slice(seq_len(min(MAX_EDGES_TO_PLOT, nrow(.)))) %>%
    mutate(
      from = node_tbl$EntrezGeneSymbol[from_idx],
      to   = node_tbl$EntrezGeneSymbol[to_idx]
    ) %>%
    filter(!is.na(from), !is.na(to), from != to) %>%
    distinct(from, to, .keep_all = TRUE)

  if (nrow(edge_df_thr) == 0) {
    return(blank_placeholder("No TOM edges recovered", "Module remains too sparse even after fallback"))
  }

  nodes_graph <- node_tbl %>%
    transmute(
      name = EntrezGeneSymbol,
      label,
      abs_kME,
      hub_rank,
      node_type,
      node_fill
    )

  edges_graph <- edge_df_thr %>%
    transmute(from, to, weight)

  used_nodes <- unique(c(edges_graph$from, edges_graph$to))
  nodes_graph <- nodes_graph %>% filter(name %in% used_nodes)

  graph_tbl <- tidygraph::tbl_graph(
    nodes = nodes_graph,
    edges = edges_graph,
    directed = FALSE
  )

  ggraph(graph_tbl, layout = "stress") +
    ggraph::geom_edge_link(
      aes(width = weight),
      colour = "grey84",
      alpha = 0.28,
      show.legend = FALSE
    ) +
    ggraph::geom_node_point(
      aes(size = abs_kME, fill = node_fill, shape = node_type),
      colour = MODULE_COLORS[module_name],
      stroke = 0.55,
      show.legend = FALSE
    ) +
    ggraph::geom_node_text(
      aes(label = ifelse(node_type == "hub" & !is.na(hub_rank) & hub_rank <= LABEL_TOP_NODES, label, "")),
      repel = TRUE,
      size = 2.75,
      fontface = "bold",
      colour = COL_TEXT,
      family = BASE_FONT_FAMILY,
      max.overlaps = Inf
    ) +
    scale_fill_identity() +
    scale_shape_manual(
      values = c(
        hub = 21,
        neighbor = 21
      )
    ) +
    scale_size_continuous(range = c(3.0, 7.2)) +
    scale_edge_width(range = c(0.08, 0.55)) +
    labs(
      title = module_network_title(module_name),
      subtitle = "Eight labelled hubs with strongest TOM-based neighbors"
    ) +
    theme_void_card()
}

# DEP-direction composition panel removed in v6.1.
# Rationale: WGCNA modules reflect co-expression structure, whereas DEP direction
# comes from a separate AD vs CN model and may be visually misleading in module portraits.

build_pathway_bubbles <- function(module_name) {
  df_path <- path_tbl %>%
    filter(Module == module_name) %>%
    filter(!is.na(Description), Description != "", !is.na(neglog10))

  if (nrow(df_path) == 0) {
    return(blank_placeholder("No enrichment available"))
  }

  df_path <- df_path %>%
    arrange(neglog10) %>%
    mutate(
      Description = shorten_pathway_label(Description),
      Description = wrap_term(Description, 22),
      Description = factor(Description, levels = Description),
      Library = factor(Library, levels = c("GO_BP", "Reactome", "KEGG"))
    )

  ggplot(df_path, aes(x = neglog10, y = Description)) +
    geom_segment(
      aes(x = 0, xend = neglog10, yend = Description),
      color = "grey88", linewidth = 0.6
    ) +
    geom_point(
      aes(size = Count),
      fill = MODULE_COLORS[module_name],
      shape = 21,
      color = "white",
      stroke = 0.85
    ) +
    scale_size_continuous(range = c(3.5, 8.5)) +
    labs(
      title = module_pathway_title(module_name),
      subtitle = expression(paste("Significant module enrichment; bubble size = gene count; x = ", -log[10], "(adjusted p)")),
      x = expression(-log[10]("adjusted p")),
      y = NULL
    ) +
    theme_card() +
    theme(
      axis.text.y = element_text(size = 9.6, color = COL_TEXT),
      panel.grid.major.x = element_line(color = COL_GRID, linewidth = 0.5)
    )
}

build_module_portrait <- function(module_name) {
  module_label <- unname(MODULE_DISPLAY_NETWORK[module_name])

  p_header <- build_header_strip(module_name, module_label)
  p_net    <- build_real_network(module_name)
  p_path   <- build_pathway_bubbles(module_name)

  bottom_row <- patchwork::wrap_plots(
    p_net, p_path,
    ncol = 2,
    widths = c(1.15, 1.00)
  )

  patchwork::wrap_plots(
    p_header,
    bottom_row,
    ncol = 1,
    heights = c(0.12, 0.88)
  )
}

##############################################################################
# 12B) PANEL D — INTEGRATED PRIORITIZATION SCATTER
##############################################################################

if (!"biological_score" %in% names(prioritization)) {
  if ("enrichment_score" %in% names(prioritization)) {
    prioritization$biological_score <- prioritization$enrichment_score
  } else if ("total_enrichment_terms" %in% names(prioritization)) {
    prioritization$biological_score <- safe_numeric(prioritization$total_enrichment_terms)
  } else {
    prioritization$biological_score <- 0
  }
}

if (!"clinical_score" %in% names(prioritization)) {
  if ("mean_abs_trait_rho" %in% names(prioritization)) {
    prioritization$clinical_score <- safe_numeric(prioritization$mean_abs_trait_rho) * 40
  } else {
    prioritization$clinical_score <- 0
  }
}

if (!"hub_score" %in% names(prioritization)) {
  if ("mean_abs_kME" %in% names(prioritization)) {
    prioritization$hub_score <- safe_numeric(prioritization$mean_abs_kME) * 30
  } else {
    prioritization$hub_score <- 10
  }
}

prioritization_plot <- prioritization %>%
  dplyr::filter(Module != "grey") %>%
  dplyr::mutate(
    biological_score = safe_numeric(biological_score),
    clinical_score = safe_numeric(clinical_score),
    hub_score = safe_numeric(hub_score),
    is_main = Module %in% TOP_MODULES_HEATMAP,
    label = dplyr::case_when(
      Module == "black" ~ "M1/black",
      Module == "brown" ~ "M2/brown",
      Module == "yellow" ~ "M3/yellow",
      TRUE ~ NA_character_
    )
  )

panel_d_prioritization <- ggplot(prioritization_plot) +
  geom_point(
    data = prioritization_plot %>% dplyr::filter(!is_main),
    aes(x = biological_score, y = clinical_score),
    color = "grey80",
    fill = "grey92",
    size = 2.5,
    shape = 21,
    stroke = 0.3,
    alpha = 0.75
  ) +
  geom_point(
    data = prioritization_plot %>% dplyr::filter(is_main),
    aes(x = biological_score, y = clinical_score, size = hub_score, fill = Module),
    color = COL_TEXT,
    shape = 21,
    stroke = 0.5,
    alpha = 0.98
  ) +
  ggrepel::geom_text_repel(
    data = prioritization_plot %>% dplyr::filter(is_main),
    aes(x = biological_score, y = clinical_score, label = label),
    size = 4.0,
    color = COL_TEXT,
    max.overlaps = Inf,
    box.padding = 0.35,
    point.padding = 0.25
  ) +
  scale_fill_manual(values = MODULE_COLORS, guide = "none") +
  scale_size_continuous(name = "Hub score", range = c(4.5, 9.5)) +
  labs(
    title = "Integrated module prioritization",
    x = "Biological richness score",
    y = "Clinical association score"
  ) +
  theme_pub() +
  theme(
    legend.position = c(0.83, 0.23),
    legend.background = element_rect(fill = "white", color = NA),
    plot.title = element_text(hjust = 0.5, face = "plain")
  )

##############################################################################
# 12C) PANEL E/F — BIOLOGICAL PORTRAITS
##############################################################################

portraits_list <- lapply(TOP_MODULES_NETWORK, build_module_portrait)
names(portraits_list) <- TOP_MODULES_NETWORK

portraits_list_main <- portraits_list[TOP_MODULES_NETWORK_MAIN]

panel_portraits_main <- patchwork::wrap_plots(
  plots = portraits_list_main,
  ncol = 1
) +
  patchwork::plot_annotation(
    title = "Hub-centered module networks and significant enrichment",
    subtitle = NULL,
    theme = theme(
      plot.title = element_text(size = TITLE_SIZE, face = "bold", hjust = 0.5, color = COL_TEXT),
      plot.margin = margin(5, 5, 5, 5)
    )
  )

# No extended black portrait is generated in this version.
# Black remains represented in panel C and panel D only, because it lacks significant enrichment.

##############################################################################
# 13) SUPPLEMENTARY PRIORITIZATION SCATTER
##############################################################################

# Compatibility with current Script 04 prioritization table.
if (!"biological_score" %in% names(prioritization)) {
  if ("enrichment_score" %in% names(prioritization)) {
    prioritization$biological_score <- prioritization$enrichment_score
  } else {
    prioritization$biological_score <- 0
  }
}

if (!"clinical_score" %in% names(prioritization)) {
  if ("mean_abs_trait_rho" %in% names(prioritization)) {
    prioritization$clinical_score <- scales::rescale(
      safe_numeric(prioritization$mean_abs_trait_rho),
      to = c(0, 1),
      from = range(safe_numeric(prioritization$mean_abs_trait_rho), na.rm = TRUE)
    )
  } else {
    prioritization$clinical_score <- 0
  }
}

if (!"hub_score" %in% names(prioritization)) {
  if ("mean_abs_kME" %in% names(prioritization)) {
    prioritization$hub_score <- scales::rescale(
      safe_numeric(prioritization$mean_abs_kME),
      to = c(0, 1),
      from = range(safe_numeric(prioritization$mean_abs_kME), na.rm = TRUE)
    )
  } else {
    prioritization$hub_score <- 0
  }
}

panel_s1_bg <- prioritization %>%
  dplyr::filter(Module != "grey")

panel_s1_fg <- prioritization %>%
  dplyr::filter(Module %in% TOP_MODULES_HEATMAP) %>%
  dplyr::mutate(label = unname(MODULE_DISPLAY_MAP[Module]))

panel_s1 <- ggplot() +
  geom_point(
    data = panel_s1_bg,
    aes(x = biological_score, y = clinical_score),
    color = "grey80",
    fill = "grey93",
    size = 4,
    shape = 21,
    stroke = 0.3
  ) +
  geom_point(
    data = panel_s1_fg,
    aes(
      x = biological_score,
      y = clinical_score,
      size = hub_score,
      fill = Module
    ),
    color = COL_TEXT,
    shape = 21,
    stroke = 0.4,
    alpha = 0.95
  ) +
  geom_text(
    data = panel_s1_fg,
