    size = 4
  ) +
  scale_fill_manual(values = MODULE_COLORS, guide = "none") +
  scale_size_continuous(name = "Hub score", range = c(4, 9)) +
  labs(
    title = "Integrated module prioritization",
    x = "Biological richness score",
    y = "Clinical association score"
  ) +
  theme_pub() +
  theme(legend.position = "top")

##############################################################################
