# Balanced main composite:
# panels a-d are placed in a true 2 x 2 grid with equal widths/heights so the
# dendrogram, barplot, heatmap and prioritization panel have the same visual
# hierarchy. The portraits occupy the lower block.
top_grid <- (
  (panel_a | panel_b) /
    (panel_c | panel_d_prioritization)
) +
  patchwork::plot_layout(
    widths = c(1, 1),
    heights = c(1, 1)
  )

figure3 <- patchwork::wrap_plots(
